{"path": "/tmp/sv-7916f89ceb51421ab9ff0e81f0320a9f/Components/Board/TaskCard.razor", "file_text": "<div class="card mb-2">
    <div class="card-body p-2">
        <h6 class="card-title mb-1">@Task.Title</h6>
        <p class="card-text mb-1 text-muted small">@Task.Assignee</p>
        <span class="badge @PriorityClass me-1">@Task.Priority</span>
        <span class="text-muted small">@Task.DueDate.ToString("MMM dd")</span>
        <div class="mt-2 d-flex gap-1">
            @if (ShowMoveLeft)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="MoveLeftAsync">← Move Left</button>
            }
            @if (ShowMoveRight)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="MoveRightAsync">Move Right →</button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public TaskItem Task { get; set; } = default!;
    [Parameter] public bool ShowMoveLeft { get; set; }
    [Parameter] public bool ShowMoveRight { get; set; }
    [Parameter] public EventCallback<int> OnMoveLeft { get; set; }
    [Parameter] public EventCallback<int> OnMoveRight { get; set; }

    private string PriorityClass => Task.Priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };

    private async Task MoveLeftAsync() => await OnMoveLeft.InvokeAsync(Task.Id);
    private async Task MoveRightAsync() => await OnMoveRight.InvokeAsync(Task.Id);
}
"}

{"path": "/tmp/sv-7916f89ceb51421ab9ff0e81f0320a9f/Components/Board/AddTaskForm.razor", "file_text": "<div class="card border-primary mt-2">
    <div class="card-body p-2">
        <div class="mb-2">
            <input type="text" class="form-control form-control-sm" placeholder="Title" @bind="title" />
        </div>
        <div class="mb-2">
            <input type="text" class="form-control form-control-sm" placeholder="Assignee" @bind="assignee" />
        </div>
        <div class="mb-2">
            <select class="form-select form-select-sm" @bind="priority">
                <option value="High">High</option>
                <option value="Medium">Medium</option>
                <option value="Low">Low</option>
            </select>
        </div>
        <div class="mb-2">
            <input type="date" class="form-control form-control-sm" @bind="dueDate" />
        </div>
        <div class="d-flex gap-1">
            <button class="btn btn-primary btn-sm" @onclick="SaveAsync" disabled="@saving">Save</button>
            <button class="btn btn-secondary btn-sm" @onclick="Cancel" disabled="@saving">Cancel</button>
        </div>
    </div>
</div>

@code {
    [Parameter] public EventCallback<TaskItem> OnSave { get; set; }
    [Parameter] public EventCallback OnCancel { get; set; }

    private string title = "";
    private string assignee = "";
    private string priority = "Medium";
    private DateTime dueDate = DateTime.Today.AddDays(7);
    private bool saving;

    private async Task SaveAsync()
    {
        if (string.IsNullOrWhiteSpace(title)) return;
        saving = true;
        await OnSave.InvokeAsync(new TaskItem(0, title, assignee, priority, dueDate, ""));
        saving = false;
    }

    private async Task Cancel() => await OnCancel.InvokeAsync();
}
"}

{"path": "/tmp/sv-7916f89ceb51421ab9ff0e81f0320a9f/Components/Board/BoardStats.razor", "file_text": "<div class="d-flex flex-wrap gap-3 mb-3 p-3 bg-light rounded">
    <div><strong>Total:</strong> @Tasks.Count</div>
    <div><strong>To Do:</strong> @Tasks.Count(t => t.Status == "To Do")</div>
    <div><strong>In Progress:</strong> @Tasks.Count(t => t.Status == "In Progress")</div>
    <div><strong>Done:</strong> @Tasks.Count(t => t.Status == "Done")</div>
    <div class="@(OverdueCount > 0 ? "text-danger" : "")">
        <strong>Overdue:</strong> @OverdueCount
    </div>
</div>

@code {
    [Parameter, EditorRequired] public List<TaskItem> Tasks { get; set; } = [];

    private int OverdueCount => Tasks.Count(t => t.DueDate < DateTime.Today && t.Status != "Done");
}
"}

{"path": "/tmp/sv-7916f89ceb51421ab9ff0e81f0320a9f/Components/Board/BoardSearchBar.razor", "file_text": "<div class="mb-3">
