    {
        var items = allTasks.Where(t => t.Status == status);
        if (!string.IsNullOrWhiteSpace(searchText))
        {
            items = items.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase));
        }
        return items.ToList();
    }

    private async Task MoveTaskAsync(int taskId, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            var idx = allTasks.FindIndex(t => t.Id == taskId);
            if (idx >= 0)
            {
                allTasks[idx] = allTasks[idx] with { Status = newStatus };
            }
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }

    private async Task HandleTaskCreatedAsync(TaskItem draft)
    {
        try
        {
            var created = await TaskService.CreateTaskAsync(draft.Title, draft.Assignee, draft.Priority, draft.DueDate);
            allTasks.Add(created);
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }
}

